15	const RUNE_BLOCK_PRICE = 60;
16	const RUNE_BLOCK_SIZE = 3;
17	
18	const policyBaseFor = (items: Item[]): number => {
19	  const itemsSum = items.reduce((acc, item) => acc + BASE_PREMIUMS[item.type], 0);
20	  const runeCount = items.filter((item) => item.type === "rune").length;
21	  const formsRuneBlock = runeCount === RUNE_BLOCK_SIZE;
22	  const runeBlockDiscount = formsRuneBlock ? runeCount * BASE_PREMIUMS.rune - RUNE_BLOCK_PRICE : 0;
23	  return itemsSum - runeBlockDiscount;
24	};
25	
26	export const runScenario = (input: unknown): unknown => {
27	  const items = (input as Scenario).steps[0].items;
28	  const policyBase = policyBaseFor(items);
29	  const premium = Math.ceil((policyBase * FIRST_INSURANCE_PERCENT) / 100) + PROCESSING_FEE;
30	  return { results: [{ premium }] };
31	};
