const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_BASE_PREMIUM = 25;
const BLOCK_PRICE = 60;
const BLOCK_SIZE = 3;

const policyBaseFor = (items: Item[]): number => {
  const countsByType = items.reduce<Record<string, number>>((acc, item) => {
    acc[item.type] = (acc[item.type] ?? 0) + 1;
    return acc;
  }, {});
  return Object.entries(countsByType).reduce((acc, [type, count]) => {
    const base = BASE_PREMIUMS[type];
    const isComponent = base === COMPONENT_BASE_PREMIUM;
    const formsBlock = isComponent && count === BLOCK_SIZE;
    return acc + (formsBlock ? BLOCK_PRICE : base * count);
  }, 0);
};
